          return (
            <div key={pt.part_type_id} className="tile" style={{
              border: isScrap ? '1.5px solid #fca5a5' : pt.is_battery ? '1.5px solid #fbbf24' : '1.5px solid #e2e8f0',
              background: isScrap ? '#fff5f5' : pt.is_battery ? '#fffbeb' : '#fff',
              padding: '10px 12px'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '8px' }}>
                <span style={{ fontWeight: 600, fontSize: '12px', color: isScrap ? '#ef4444' : '#1e293b', textDecoration: isScrap ? 'line-through' : 'none' }}>
                  {pt.name}
                </span>
                <button onClick={() => toggleScrap(pt.part_type_id)} style={{
                  padding: '2px 10px', borderRadius: '6px', border: 'none', cursor: 'pointer', fontSize: '11px', fontWeight: 600,
                  background: isScrap ? '#ef4444' : '#f1f5f9',
                  color: isScrap ? '#fff' : '#64748b'
                }}>
                  {isScrap ? '✕ Scrap' : 'Mark Scrap'}
                </button>
              </div>
              {pt.is_battery && (
                <div style={{ fontSize: '10px', color: '#92400e', background: '#fef3c7', padding: '3px 8px', borderRadius: '4px', marginBottom: '6px' }}>
                  ⚡ R2V3 battery inspection required at removal
                </div>
              )}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '4px' }}>
                <div>
                  <div style={{ fontSize: '9px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '2px' }}>Make</div>
                  <input value={state.make || ''} onChange={e => updateField(pt.part_type_id, 'make', e.target.value)}
                    placeholder="e.g. Samsung" style={{ width: '100%', height: '24px', border: '1px solid #e2e8f0', borderRadius: '4px', padding: '0 6px', fontSize: '11px' }} />
                </div>
                <div>
                  <div style={{ fontSize: '9px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '2px' }}>Model/Spec</div>
                  <input value={state.model || ''} onChange={e => updateField(pt.part_type_id, 'model', e.target.value)}
                    placeholder="e.g. 512GB NVMe" style={{ width: '100%', height: '24px', border: '1px solid #e2e8f0', borderRadius: '4px', padding: '0 6px', fontSize: '11px' }} />
                </div>
                <div>
                  <div style={{ fontSize: '9px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '2px' }}>Condition</div>
                  <select value={state.condition || 'B'} onChange={e => updateField(pt.part_type_id, 'condition', e.target.value)}
                    style={{ width: '100%', height: '24px', border: '1px solid #e2e8f0', borderRadius: '4px', padding: '0 4px', fontSize: '11px' }}>
                    <option value="A">A — Excellent</option>
                    <option value="B">B — Good</option>
                    <option value="C">C — Fair</option>
                    <option value="F">F — Faulty</option>
                    <option value="U">U — Unknown</option>
                  </select>
                </div>
                <div>
                  <div style={{ fontSize: '9px', color: '#94a3b8', textTransform: 'uppercase', marginBottom: '2px' }}>Notes</div>
                  <input value={state.notes || ''} onChange={e => updateField(pt.part_type_id, 'notes', e.target.value)}
                    placeholder="Optional" style={{ width: '100%', height: '24px', border: '1px solid #e2e8f0', borderRadius: '4px', padding: '0 6px', fontSize: '11px' }} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: '12px', borderTop: '1px solid #f1f5f9' }}>
        <div style={{ fontSize: '11px', color: '#94a3b8' }}>
          {scrapCount > 0 ? scrapCount + ' part(s) marked as scrap' : 'All parts marked as salvageable'}
        </div>
        <button onClick={submit} style={{
          height: '36px', padding: '0 20px', background: '#1A5C3A', color: '#fff', border: 'none',
          borderRadius: '7px', fontSize: '13px', fontWeight: 500, cursor: 'pointer'
        }}>
          ✓ Log all parts
        </button>
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
